import xml.etree.ElementTree as ET
from xml.etree.ElementTree import parse
from xml.validators.validatorxml import Validator, XSDValidator

def validate_and_read_xml(xsd_file, xml_file):
    xsd_parser = XSDValidator()
    with open(xsd_file, "rb") as xsd:
        schema = xsd_parser.validate(ET.fromstring(xsd))

    try:
        with open(xml_file, "rb") as xml:
            tree = ET.parse(xml)
            schema.validate(tree.getroot())
            return ET.tostring(tree, encoding='utf8', method='html')
    except Exception as e:
        print("Invalid XML document.")
        raise ValueError("XML validation failed with error:", str(e))